    expect(parseArgs(["bridge"]).command).toBe("start");
    expect(parseArgs(["bridge"]).deprecatedBridgeAlias).toBe(true);
  });

  test("parses explicit start options", () => {
    expect(
      parseArgs([
        "start",
        "--host",
        "127.0.0.1",
        "--port",
        "5555",
        "--mode",
        "demo",
        "--control-plane-url",
