    expect(usage()).toContain("offdex stop");
    expect(usage()).toContain("https://offdexapp.vercel.app");
    expect(usage()).toContain("https://github.com/Dhruv2mars/offdex/issues");
    expect(usage()).not.toContain("offdex bridge [options]");
