    process.exit(0);
  } catch (error) {
    spinner.stop();
    console.error("offdex: bridge did not start cleanly");
    console.error(`offdex: see log at ${logPath}`);
    if (error instanceof Error) {
      console.error(`offdex: ${error.message}`);
    }
    process.exit(1);
  }
}

